# Integration test with vcrpy
import vcr
import pytest
from agent.core import CustomerServiceAgent

@pytest.fixture
def agent():
    return CustomerServiceAgent(model="claude-haiku-4-5")

@vcr.use_cassette(
    "tests/cassettes/order_status_lookup.yaml",
    record_mode="none",  # fail if cassette missing
)
def test_agent_retrieves_order_status(agent):
    response = agent.run(
        "What is the status of order #12345?",
        context={"customer_id": "cust_001"},
    )
    # Real LLM response from cassette
    assert response.tool_calls[0].tool == "lookup_order"
    assert response.tool_calls[0].params["order_id"] == "12345"
    assert "status" in response.text.lower()

# To record a new cassette, set record_mode="new_episodes" and run once
# Then commit the cassette file to version control

# Hybrid scorer: rule-based fast check, then LLM judge for quality
from anthropic import Anthropic

client = Anthropic()

def score_response(query: str, response: str, expected_criteria: dict) -> dict:
    results = {}

    # Rule-based checks (fast, free)
    if expected_criteria.get("must_cite_source"):
        results["citation_present"] = bool(
            re.search(r"\[Source:|According to", response)
        )

    if expected_criteria.get("no_pii"):
        results["pii_absent"] = not bool(
            re.search(r"\b\d{3}[-.]\d{3}[-.]\d{4}\b", response)  # phone number
        )

    # LLM-as-judge (slower, costs tokens)
    if expected_criteria.get("factual_accuracy"):
        judge_prompt = f"""
        Query: {query}
        Response: {response}
        Expected answer: {expected_criteria['expected_answer']}

        Score the response's factual accuracy from 0.0 (wrong) to 1.0 (correct).
        Reply with only a float.
        """
        judge_resp = client.messages.create(
            model="claude-haiku-4-5",
            max_tokens=10,
            messages=[{"role": "user", "content": judge_prompt}],
        )
        results["factual_accuracy"] = float(judge_resp.content[0].text.strip())

    return results
